  1→import { type RecordId, type Surreal } from "surrealdb";
  2→import type { ObservationSummary } from "../../shared/contracts";
  3→import {
  4→  listConversationEntities,
  5→  listWorkspaceOpenQuestions,
  6→  listWorkspaceProjectSummaries,
  7→  listWorkspaceRecentDecisions,
  8→  type ConversationEntity,
  9→  type WorkspaceDecisionSummary,
 10→  type WorkspaceProjectSummary,
 11→  type WorkspaceQuestionSummary,
 12→} from "../graph/queries";
 13→import { listWorkspaceOpenObservations } from "../observation/queries";
 14→import { chatComponentSystemPrompt } from "./chat-component-system-prompt";
 15→
 16→export type ChatContext = {
 17→  conversationEntities: ConversationEntity[];
 18→  workspaceSummary: {
 19→    projects: WorkspaceProjectSummary[];
 20→    recentDecisions: WorkspaceDecisionSummary[];
 21→    openQuestions: WorkspaceQuestionSummary[];
 22→    openObservations: ObservationSummary[];
 23→  };
 24→};
 25→
 26→type ChatContextLoaders = {
 27→  listConversationEntities: typeof listConversationEntities;
 28→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 29→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 30→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 31→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 32→};
 33→
 34→export async function buildChatContext(input: {
 35→  surreal: Surreal;
 36→  conversationRecord: RecordId<"conversation", string>;
 37→  workspaceRecord: RecordId<"workspace", string>;
 38→  loaders?: ChatContextLoaders;
 39→  inheritedEntityIds?: RecordId[];
 40→}): Promise<ChatContext> {
 41→  const loaders = input.loaders ?? {
 42→    listConversationEntities,
 43→    listWorkspaceProjectSummaries,
 44→    listWorkspaceRecentDecisions,
 45→    listWorkspaceOpenQuestions,
 46→    listWorkspaceOpenObservations,
 47→  };
 48→
 49→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations] = await Promise.all([
 50→    loaders.listConversationEntities({
 51→      surreal: input.surreal,
 52→      conversationRecord: input.conversationRecord,
 53→      workspaceRecord: input.workspaceRecord,
 54→      limit: 60,
 55→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 56→        ? { inheritedEntityIds: input.inheritedEntityIds }
 57→        : {}),
 58→    }),
 59→    loaders.listWorkspaceProjectSummaries({
 60→      surreal: input.surreal,
 61→      workspaceRecord: input.workspaceRecord,
 62→      limit: 20,
 63→    }),
 64→    loaders.listWorkspaceRecentDecisions({
 65→      surreal: input.surreal,
 66→      workspaceRecord: input.workspaceRecord,
 67→      limit: 12,
 68→    }),
 69→    loaders.listWorkspaceOpenQuestions({
 70→      surreal: input.surreal,
 71→      workspaceRecord: input.workspaceRecord,
 72→      limit: 12,
 73→    }),
 74→    loaders.listWorkspaceOpenObservations({
 75→      surreal: input.surreal,
 76→      workspaceRecord: input.workspaceRecord,
 77→      limit: 10,
 78→    }),
 79→  ]);
 80→
 81→  return {
 82→    conversationEntities,
 83→    workspaceSummary: {
 84→      projects,
 85→      recentDecisions,
 86→      openQuestions,
 87→      openObservations,
 88→    },
 89→  };
 90→}
 91→
 92→function formatConversationEntities(entities: ConversationEntity[]): string {
 93→  if (entities.length === 0) {
 94→    return "- none";
 95→  }
 96→
 97→  return entities
 98→    .slice(0, 20)
 99→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
100→    .join("\n");
101→}
102→
103→function formatProjectList(projects: WorkspaceProjectSummary[]): string {
104→  if (projects.length === 0) {
105→    return "- none";
106→  }
107→
108→  return projects
109→    .slice(0, 15)
110→    .map((project) => `- ${project.name} [id: ${project.id}] active tasks: ${project.activeTaskCount}`)
111→    .join("\n");
112→}
113→
114→function formatDecisionList(decisions: WorkspaceDecisionSummary[]): string {
115→  if (decisions.length === 0) {
116→    return "- none";
117→  }
118→
119→  return decisions
120→    .slice(0, 15)
121→    .map((decision) => {
122→      const project = decision.project ? ` project: ${decision.project}` : "";
123→      return `- ${decision.name} [id: ${decision.id}] status: ${decision.status}${project}`;
124→    })
125→    .join("\n");
126→}
127→
128→function formatQuestionList(questions: WorkspaceQuestionSummary[]): string {
129→  if (questions.length === 0) {
130→    return "- none";
131→  }
132→
133→  return questions
134→    .slice(0, 15)
135→    .map((question) => {
136→      const project = question.project ? ` project: ${question.project}` : "";
137→      return `- ${question.name} [id: ${question.id}]${project}`;
138→    })
139→    .join("\n");
140→}
141→
142→function formatObservationList(observations: ObservationSummary[]): string {
143→  if (observations.length === 0) {
144→    return "- none";
145→  }
146→
147→  return observations
148→    .slice(0, 10)
149→    .map((observation) => {
150→      const category = observation.category ? `, ${observation.category}` : "";
151→      return `- [${observation.severity}] ${observation.text} (by ${observation.sourceAgent}, ${observation.status}${category})`;
152→    })
153→    .join("\n");
154→}
155→
156→export function buildSystemPrompt(context: ChatContext): string {
157→  return [
158→    "You are the Orchestrator agent for a workspace-aware project intelligence system.",
159→    "You are a **thin orchestrator**: your job is to decide which tools and subagents to invoke, control sequencing, and synthesize user-facing responses.",
160→    "You have access to a workspace-scoped knowledge graph stored in SurrealDB.",
161→    "Never assume data from other workspaces.",
162→    "",
