 1→import type { EntityCategory, EntityKind, ExtractedEntity, ExtractedRelationship } from "../../shared/contracts";
 2→import { normalizeName } from "./normalize";
 3→import { shouldDisplayExtraction } from "./validation";
 4→
 5→type ExtractableEntityKind = Exclude<EntityKind, "workspace" | "observation">;
 6→
 7→type CardEntity = {
 8→  kind: ExtractableEntityKind;
 9→  name: string;
10→  confidence: number;
11→  status: "captured";
12→  category?: EntityCategory;
13→};
14→
15→export function buildExtractionComponentBlock(
16→  entities: ExtractedEntity[],
17→  relationships: ExtractedRelationship[],
18→  displayThreshold: number,
19→): string | undefined {
20→  const summaryEntities = new Map<string, CardEntity>();
21→
22→  for (const entity of [...entities].sort((a, b) => b.confidence - a.confidence)) {
23→    if (entity.kind === "workspace" || entity.kind === "observation" || !shouldDisplayExtraction(entity.confidence, displayThreshold)) {
24→      continue;
25→    }
26→
27→    const name = entity.text.trim();
28→    if (name.length === 0) {
29→      continue;
30→    }
31→
32→    const key = `${entity.kind}:${normalizeName(name)}`;
33→    if (!summaryEntities.has(key)) {
34→      summaryEntities.set(key, {
35→        kind: entity.kind as ExtractableEntityKind,
36→        name,
37→        confidence: entity.confidence,
38→        status: "captured",
39→        ...(entity.category ? { category: entity.category } : {}),
40→      });
41→    }
42→  }
43→
44→  const cards = [...summaryEntities.values()].slice(0, 6);
45→  if (cards.length === 0) {
46→    return undefined;
47→  }
48→
49→  const componentSpec = cards.length === 1
50→    ? {
51→        type: "EntityCard",
52→        props: cards[0],
53→      }
54→    : {
55→        type: "ExtractionSummary",
56→        props: {
57→          title: "Captured from your latest message",
58→          entities: cards,
59→          relationshipCount: relationships.filter((relationship) =>
60→            shouldDisplayExtraction(relationship.confidence, displayThreshold)
61→          ).length,
62→        },
63→      };
64→
65→  return ["```component", JSON.stringify(componentSpec, null, 2), "```"].join("\n");
66→}
