119→function WorkItemSuggestion(props: WorkItemSuggestionProps) {
120→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
121→  const [status, setStatus] = useState<WorkItemStatus>("pending");
122→
123→  async function handleAccept() {
124→    if (!workspaceId || status !== "pending") return;
125→    setStatus("accepting");
126→    try {
127→      await acceptWorkItem(workspaceId, props);
128→      setStatus("accepted");
129→    } catch {
