152→function sanitizeSuggestions(suggestions: string[], limit: number): string[] {
153→  return [...new Set(suggestions.map((value) => value.trim()))]
154→    .filter((value) => value.length > 0 && value.length <= 140)
155→    .slice(0, limit);
156→}
157→
158→function buildSuggestionAnchors(
159→  latestUserText: string,
160→  entities: Array<{ kind: EntityKind; text: string; confidence: number }>,
161→  tools: string[],
162→): string[] {
163→  const anchors = [...tools, ...entities.map((entity) => entity.text)];
164→  const properNouns = [
165→    ...(latestUserText.match(/\b[A-Z][A-Za-z0-9_-]{2,}\b/g) ?? []),
166→    ...entities.flatMap((entity) => entity.text.match(/\b[A-Z][A-Za-z0-9_-]{2,}\b/g) ?? []),
167→  ];
168→
169→  anchors.push(...properNouns);
170→  return [...new Set(anchors.map((value) => value.trim()))]
171→    .filter((value) => value.length >= 3)
172→    .slice(0, 12);
173→}
174→
175→function formatSuggestionAnchors(anchors: string[]): string {
176→  if (anchors.length === 0) {
177→    return "(none)";
178→  }
179→
180→  return anchors.map((anchor) => `- ${anchor}`).join("\n");
181→}
182→
183→function formatContextRows(rows: MessageContextRow[]): string {
184→  if (rows.length === 0) {
185→    return "(no prior messages)";
186→  }
187→
188→  return rows.map((row) => `${row.role.toUpperCase()}: ${row.text}`).join("\n");
189→}
190→
191→function formatLatestExtractionContext(
192→  entities: Array<{ kind: EntityKind; text: string; confidence: number }>,
193→  tools: string[],
194→): string {
195→  const entityLines = entities
196→    .slice()
197→    .sort((a, b) => b.confidence - a.confidence)
198→    .slice(0, 10)
199→    .map((entity) => `${entity.kind}: ${entity.text} (${entity.confidence.toFixed(2)})`);
200→  const toolLines = tools.slice(0, 10).map((tool) => `tool: ${tool}`);
201→  const lines = [...entityLines, ...toolLines];
202→  return lines.length > 0 ? lines.join("\n") : "(no extracted entities or tools)";
203→}
204→
205→function keepSuggestionsWithAnchors(suggestions: string[], anchors: string[]): string[] {
206→  if (anchors.length === 0) {
207→    return [];
208→  }
209→
210→  return suggestions.filter((suggestion) => includesAnyAnchor(suggestion, anchors));
211→}
212→
213→function includesAnyAnchor(suggestion: string, anchors: string[]): boolean {
214→  const normalizedSuggestion = normalizeForAnchorMatch(suggestion);
215→  for (const anchor of anchors) {
216→    const normalizedAnchor = normalizeForAnchorMatch(anchor);
217→    if (normalizedAnchor.length === 0) {
218→      continue;
219→    }
220→    if (normalizedSuggestion.includes(normalizedAnchor)) {
221→      return true;
222→    }
223→  }
224→
225→  return false;
226→}
227→
228→function normalizeForAnchorMatch(value: string): string {
229→  return value
230→    .toLowerCase()
231→    .replace(/[^a-z0-9\s]/g, " ")
232→    .replace(/\s+/g, " ")
233→    .trim();
234→}
